IOT_QUESTIONS_PART7 = [{'question': 'What personal data do IoT devices typically collect and what GDPR obligations does this create for organisations deploying them?', 'options': [{'text': 'IoT devices only collect technical data like temperature readings which is not personal data under GDPR', 'explanation': 'IoT devices frequently collect data that qualifies as personal data under GDPR including location data, behavioural patterns, biometric data, and usage data that can identify individuals. Even technical data can become personal data when combined with other information.', 'correct': False}, {'text': 'IoT devices collect location data usage patterns biometric data and behavioural information creating GDPR obligations for lawful basis consent data minimisation security and individual rights', 'explanation': 'Correct. IoT personal data includes: GPS location from wearables, home occupancy patterns from smart home devices, health data from fitness trackers, voice recordings from smart speakers, facial recognition from cameras, and purchasing behaviour from smart retail. GDPR obligations include: establishing lawful basis for processing, obtaining consent where required, data minimisation, security measures, privacy notices, and supporting individual rights including erasure.', 'correct': True}, {'text': 'GDPR does not apply to IoT devices as they are hardware products not software services', 'explanation': 'GDPR applies to any processing of personal data regardless of the technology used. IoT devices that collect, transmit, or store personal data are subject to GDPR obligations for the organisations deploying them.', 'correct': False}, {'text': 'GDPR IoT obligations only apply to organisations based in the European Union not to organisations in other countries deploying IoT devices', 'explanation': 'GDPR applies to any organisation processing personal data of EU residents regardless of where the organisation is based. A New Zealand organisation with EU customers deploying IoT that processes their data must comply with GDPR.', 'correct': False}], 'overall_explanation': 'IoT GDPR compliance requirements: data protection impact assessment (DPIA) for high-risk IoT processing, privacy by design embedding data protection into IoT architecture, data minimisation collecting only necessary data, purpose limitation using data only for stated purposes, storage limitation retaining data only as long as necessary, security measures proportionate to risk, and clear privacy notices informing users what data is collected.', 'domain': 'IoT Security - Privacy and Compliance'}, {'question': 'What is Privacy by Design in IoT and how does it differ from adding privacy controls after deployment?', 'options': [{'text': 'Privacy by Design means adding a privacy policy document to IoT products before they are sold', 'explanation': 'Privacy by Design is a technical and architectural approach not just documentation. It means embedding privacy protections into the design of IoT systems from the beginning rather than adding them as afterthoughts.', 'correct': False}, {'text': 'Privacy by Design embeds data minimisation encryption consent mechanisms and user rights into IoT architecture from the start making privacy the default rather than requiring users to opt in', 'explanation': 'Correct. Privacy by Design principles for IoT: proactive prevention of privacy risks before deployment, privacy as the default setting without user action required, privacy embedded into system architecture, full functionality without sacrificing privacy, end-to-end security protecting personal data throughout lifecycle, visibility and transparency about data practices, and respect for user privacy with user-centric controls.', 'correct': True}, {'text': 'Privacy by Design is only required for IoT devices sold in the European Union and is not relevant elsewhere', 'explanation': 'Privacy by Design is a globally recognised approach incorporated into GDPR and recommended by privacy regulators worldwide including in New Zealand, Australia, Canada, and the UK. It is not geographically limited.', 'correct': False}, {'text': 'Privacy by Design and privacy added after deployment provide equivalent protection when implemented correctly', 'explanation': 'Privacy added after deployment is significantly less effective than Privacy by Design. Retrofitting privacy protections into deployed IoT systems is costly, often incomplete, and may be architecturally impossible for some controls. Privacy by Design prevents these limitations.', 'correct': False}], 'overall_explanation': 'Privacy by Design for IoT implementation: collect minimum data required, encrypt data in transit and at rest by default, provide granular user consent controls, implement automatic data deletion, design for easy exercise of subject access rights, conduct DPIAs before deployment, and build audit logging for all personal data access. Retrofitting these controls post-deployment is expensive and often incomplete.', 'domain': 'IoT Security - Privacy and Compliance'}, {'question': 'A smart speaker collects voice recordings to improve AI responses. Under GDPR what specific obligations apply to the processing of these voice recordings?', 'options': [{'text': 'Voice recordings from smart speakers are not personal data because they are processed automatically without human review', 'explanation': 'Automated processing does not remove personal data status under GDPR. Voice recordings can identify individuals by voice characteristics and content making them personal data subject to GDPR regardless of automated processing.', 'correct': False}, {'text': 'Voice recordings are likely biometric data requiring explicit consent a DPIA transparent disclosure and strong security measures with clear retention limits', 'explanation': 'Correct. Voice recordings processed to identify individuals are biometric data under GDPR Article 9 requiring explicit consent (not just legitimate interest), a Data Protection Impact Assessment due to high risk processing, clear disclosure in privacy notices, strong security measures, defined retention periods, and easy withdrawal of consent including deletion of historical recordings.', 'correct': True}, {'text': 'Smart speaker voice recordings only require the same GDPR obligations as any other personal data with no special requirements', 'explanation': 'Voice recordings used to identify individuals are biometric data which is a special category under GDPR Article 9 requiring explicit consent and higher protection standards than standard personal data.', 'correct': False}, {'text': 'GDPR consent for voice recording collection only needs to be obtained once at device setup and applies permanently', 'explanation': 'GDPR consent must be freely given, specific, informed, and unambiguous. Individuals must be able to withdraw consent at any time. Consent obtained once at setup without ongoing right to withdraw does not meet GDPR requirements.', 'correct': False}], 'overall_explanation': 'Voice recording GDPR compliance: explicit consent for biometric processing, clear purpose limitation (not reused for undisclosed purposes), DPIA documenting risks and mitigations, transparent privacy notice explaining voice data use, easy consent withdrawal including historical recording deletion, strong encryption for stored recordings, and defined retention limits with automatic deletion.', 'domain': 'IoT Security - Privacy and Compliance'}, {'question': 'What is the California Consumer Privacy Act (CCPA) and how does it apply to IoT devices used in California?', 'options': [{'text': 'CCPA only applies to California-based companies and does not affect organisations outside California that have California customers', 'explanation': 'CCPA applies to any business that collects personal information from California residents regardless of where the business is located. An organisation anywhere in the world with California customers must comply if they meet the CCPA thresholds.', 'correct': False}, {'text': 'CCPA grants California residents rights to know what personal data IoT devices collect opt out of data sale and request deletion applying to any business meeting revenue or data volume thresholds with California customers', 'explanation': 'Correct. CCPA applies to businesses meeting thresholds (over  annual revenue, or processing data of 100,000+ consumers, or deriving 50%+ revenue from selling personal information) that collect personal information from California residents. IoT obligations: disclose what data is collected, provide opt-out of data sale, honour deletion requests, and implement reasonable security measures.', 'correct': True}, {'text': 'CCPA is identical to GDPR and organisations that comply with GDPR automatically comply with CCPA', 'explanation': 'CCPA and GDPR share principles but differ in requirements, scope, and specific obligations. GDPR compliance does not automatically ensure CCPA compliance. Both must be assessed separately.', 'correct': False}, {'text': 'CCPA does not apply to IoT devices because they are hardware products covered by product liability law not privacy law', 'explanation': 'CCPA applies to the personal information collected and processed by IoT devices regardless of whether the IoT product is hardware. The law regulates data processing practices not product types.', 'correct': False}], 'overall_explanation': 'CCPA IoT compliance requirements: privacy notice disclosing categories of personal information collected by IoT devices, opt-out mechanism for sale of IoT-collected personal information, process for honouring deletion requests including data on IoT devices and cloud platforms, reasonable security measures, and non-discrimination against consumers who exercise CCPA rights.', 'domain': 'IoT Security - Privacy and Compliance'}, {'question': 'What is the EU Cyber Resilience Act and what obligations will it create for IoT product manufacturers?', 'options': [{'text': 'The EU Cyber Resilience Act is a voluntary framework that IoT manufacturers can optionally adopt for competitive advantage', 'explanation': 'The EU Cyber Resilience Act is mandatory legislation not a voluntary framework. IoT products that do not meet its requirements cannot be sold in the EU market.', 'correct': False}, {'text': 'The EU Cyber Resilience Act mandates security by design for IoT products sold in the EU including vulnerability handling secure defaults security updates and software bill of materials requirements', 'explanation': 'Correct. The EU Cyber Resilience Act requires: security by design for all products with digital elements sold in the EU, vulnerability handling and disclosure processes, security updates for the product support lifetime, no known exploitable vulnerabilities at time of release, secure default configurations, software bill of materials, and CE marking requiring conformity assessment for higher-risk products.', 'correct': True}, {'text': 'The EU Cyber Resilience Act only applies to critical infrastructure operators not to consumer IoT manufacturers', 'explanation': 'The EU Cyber Resilience Act applies to manufacturers of products with digital elements sold in the EU market regardless of whether they serve critical infrastructure or consumer markets. It covers a broad range of IoT products.', 'correct': False}, {'text': 'The EU Cyber Resilience Act has been indefinitely postponed and will not take effect in the foreseeable future', 'explanation': 'The EU Cyber Resilience Act passed into law and manufacturers have a transition period to comply. It represents a significant mandatory IoT security baseline for the EU market.', 'correct': False}], 'overall_explanation': 'EU Cyber Resilience Act key requirements: security by design and default, no known exploitable vulnerabilities at market release, vulnerability disclosure programme, security updates for minimum 5 years after last sale, SBOM provision, secure configuration as default, access control for functionality, and data minimisation. Non-compliance can result in product withdrawal from EU market and financial penalties.', 'domain': 'IoT Security - Privacy and Compliance'}, {'question': 'What is an IoT security governance framework and what key policies must it include?', 'options': [{'text': 'IoT security governance only requires a password policy as credential security is the primary IoT risk', 'explanation': 'IoT security governance encompasses much more than password policy. Comprehensive governance addresses the full IoT lifecycle from procurement through decommissioning across all security domains.', 'correct': False}, {'text': 'IoT security governance must include procurement security requirements asset inventory management network segmentation standards vendor access controls update management and incident response procedures', 'explanation': 'Correct. IoT security governance framework: procurement policy (vendor assessment, security requirements in contracts), asset management (inventory, lifecycle tracking), network security standards (VLAN requirements, segmentation), authentication and identity standards (unique credentials, PKI), update management (patch timelines, OTA security), vendor and third-party access controls, incident response procedures, and decommissioning standards (data wiping, credential revocation).', 'correct': True}, {'text': 'IoT security governance frameworks are only necessary for organisations with dedicated IoT security teams', 'explanation': 'IoT security governance is necessary for any organisation deploying IoT devices regardless of team size. Governance frameworks provide the policies and procedures that guide secure IoT deployment without requiring a dedicated team.', 'correct': False}, {'text': 'IoT governance frameworks should be outsourced entirely to IoT vendors who are better positioned to define security requirements', 'explanation': 'IoT governance must reflect the deploying organisation risk tolerance, regulatory requirements, and operational context. Vendors can contribute input but the governance framework must be owned and maintained by the deploying organisation.', 'correct': False}], 'overall_explanation': 'IoT governance framework structure: IoT Security Policy (high-level requirements and principles), IoT Standards (specific technical requirements for each security domain), IoT Procedures (step-by-step processes for procurement, deployment, monitoring, incident response, decommissioning), and IoT Guidelines (best practice guidance for specific technologies or use cases). Review and update annually or after significant incidents.', 'domain': 'IoT Security - Privacy and Compliance'}, {'question': 'What data minimisation means for IoT deployments and why is it both a privacy requirement and a security benefit?', 'options': [{'text': 'Data minimisation means using the smallest possible IoT devices to reduce physical storage requirements', 'explanation': 'Data minimisation in privacy and security context refers to collecting only the minimum personal data necessary for the stated purpose not to physical device size.', 'correct': False}, {'text': 'Data minimisation means collecting only the minimum data necessary for the stated purpose reducing privacy risk regulatory liability and the value of the data to attackers if breached', 'explanation': 'Correct. Data minimisation is required by GDPR and benefits security: less data collected means less data at risk if devices are compromised, smaller data sets reduce breach notification scope and regulatory liability, attackers gain less intelligence from compromised devices, storage and transmission security requirements are reduced, and retention period management is simplified when less data is held.', 'correct': True}, {'text': 'Data minimisation is a regulatory requirement that conflicts with IoT device functionality and should be balanced against operational needs', 'explanation': 'Data minimisation and IoT functionality are not inherently in conflict. Well-designed IoT systems can achieve their operational objectives while collecting only the data genuinely required. Privacy by design incorporates data minimisation from the start.', 'correct': False}, {'text': 'Data minimisation only applies to personal data and has no relevance for IoT devices collecting only operational or technical data', 'explanation': 'Data minimisation principles apply to all IoT data collection. Unnecessary operational data collection increases storage costs, creates additional security risk surface, and may unexpectedly become personal data through aggregation with other datasets.', 'correct': False}], 'overall_explanation': 'Data minimisation implementation for IoT: define specific purposes for each data element before collection, collect only data needed for those purposes, implement automatic data deletion when retention period expires, aggregate or anonymise data where individual-level data is not required, review data collection scope regularly as purposes evolve, and document data minimisation decisions for regulatory accountability.', 'domain': 'IoT Security - Privacy and Compliance'}, {'question': 'What are the key elements of an IoT supply chain security programme and why is supply chain risk particularly significant for IoT?', 'options': [{'text': 'IoT supply chain security only requires verifying that devices arrive undamaged from the manufacturer', 'explanation': 'Physical damage inspection is one minor element. IoT supply chain security encompasses vendor security assessment, component integrity, firmware authenticity, and the entire chain from component manufacture through software development to device deployment.', 'correct': False}, {'text': 'IoT supply chain security requires vendor assessment firmware authenticity verification SBOM review component provenance tracking and contractual security requirements throughout the supply chain', 'explanation': 'Correct. IoT supply chain security is particularly significant because: compromised firmware can affect millions of devices simultaneously, hardware backdoors may be undetectable through software testing, counterfeit components may fail to meet security specifications, and malicious code in open source components used in firmware affects all devices using that firmware. Key elements: vendor security assessment, SBOM review, firmware signing verification, component provenance, and contractual obligations.', 'correct': True}, {'text': 'IoT supply chain security is exclusively the responsibility of IoT manufacturers with no obligations for deploying organisations', 'explanation': 'Deploying organisations share supply chain security responsibility. They must assess vendor security practices, verify firmware authenticity before deployment, include security requirements in procurement contracts, and monitor for supply chain compromise indicators.', 'correct': False}, {'text': 'Supply chain attacks against IoT are theoretical and have not occurred in real-world deployments', 'explanation': 'Supply chain attacks against IoT are well documented including SolarWinds demonstrating the pattern applied to IoT software supply chains, compromised router firmware delivered through official channels, and counterfeit IoT devices with pre-installed malware discovered in enterprise deployments.', 'correct': False}], 'overall_explanation': 'IoT supply chain security programme: vendor security questionnaires and assessments before procurement, firmware authenticity verification using manufacturer signatures, SBOM review for known vulnerable components, contractual security requirements including breach notification, physical security inspection for high-value deployments, post-deployment monitoring for indicators of supply chain compromise, and incident response procedures for suspected supply chain attacks.', 'domain': 'IoT Security - Privacy and Compliance'}, {'question': 'What is the principle of security by default for IoT devices and how does it differ from security by design?', 'options': [{'text': 'Security by default and security by design are identical concepts that mean the same thing', 'explanation': 'Security by design and security by default are related but distinct concepts. Security by design is about embedding security throughout the development process. Security by default specifically means the device ships in its most secure configuration without requiring user action.', 'correct': False}, {'text': 'Security by default means devices ship in the most secure configuration with unnecessary features disabled strong authentication required and privacy protections active without requiring user configuration', 'explanation': 'Correct. Security by default means: the device works securely out of the box, all unnecessary services are disabled by default, strong authentication is required from first use, privacy-protective settings are active without user action, and insecure features require explicit user opt-in rather than opt-out. Users who do nothing receive a secure device. Security by design is the process of building these defaults into the development lifecycle.', 'correct': True}, {'text': 'Security by default means providing users with a default password that they can change after setup if they choose', 'explanation': 'Default passwords that users may or may not change are the opposite of security by default. True security by default requires unique credentials or forced credential creation at first use rather than optional password changes.', 'correct': False}, {'text': 'Security by default only applies to enterprise IoT products and consumer devices are exempt from this requirement', 'explanation': 'Security by default applies to all IoT devices. The UK PSTI Act 2024 and EU Cyber Resilience Act both require security by default for consumer and enterprise IoT products sold in their jurisdictions.', 'correct': False}], 'overall_explanation': 'Security by default implementation: disable all unused network services at manufacture, require unique credential creation at first setup (or ship with unique per-device credentials), enable automatic security updates by default, implement strictest privacy settings as default, disable debug interfaces in production firmware, and test that factory reset returns devices to secure default state not insecure factory configuration.', 'domain': 'IoT Security - Privacy and Compliance'}, {'question': 'What IoT security certifications and standards can organisations use to evaluate the security of IoT products during procurement?', 'options': [{'text': 'There are no established IoT security certifications making procurement evaluation entirely subjective', 'explanation': 'Multiple established IoT security certifications and standards exist including ETSI EN 303 645, UL IoT Security Rating, ioXt Alliance certification, and others that provide objective procurement evaluation criteria.', 'correct': False}, {'text': 'ETSI EN 303 645 UL IoT Security Rating ioXt Alliance certification and alignment with NIST SP 800-213 provide objective security evaluation criteria for IoT procurement decisions', 'explanation': 'Correct. IoT security certifications: ETSI EN 303 645 is the baseline European IoT security standard covering 13 provisions, UL IoT Security Rating provides tiered security assessment for connected products, ioXt Alliance certifies against a baseline security standard, NIST SP 800-213 provides a framework for IoT security requirement definition, and ISO 27001 certification of the vendor demonstrates security management system maturity.', 'correct': True}, {'text': 'ISO 27001 certification of an IoT vendor guarantees that their products meet all IoT security requirements', 'explanation': "ISO 27001 certifies an organisation's information security management system not the security of specific products. ISO 27001 is a useful indicator of vendor security maturity but does not guarantee product security compliance with IoT-specific requirements.", 'correct': False}, {'text': 'CE marking on IoT products sold in Europe guarantees they meet cybersecurity requirements', 'explanation': 'Traditional CE marking does not cover cybersecurity requirements. The EU Cyber Resilience Act will introduce cybersecurity CE marking requirements but this is a recent development and existing CE marking does not address cybersecurity.', 'correct': False}], 'overall_explanation': 'IoT procurement security evaluation: require ETSI EN 303 645 or equivalent compliance evidence, request penetration testing results and responsible disclosure programme details, review published CVE history and patch response times, verify firmware signing capability, confirm minimum support lifetime commitment, request SBOM, and include contractual security requirements with audit rights. Certification claims should be verified against actual product testing where possible.', 'domain': 'IoT Security - Privacy and Compliance'}]